-- 4. Insert dummy users into auth.users (for subscriptions)
-- Note: This is for testing only
DO $$
DECLARE
  user_ids uuid[] := ARRAY[
    'a5e00001-0000-0000-0000-000000000001',
    'a5e00002-0000-0000-0000-000000000002',
    'a5e00003-0000-0000-0000-000000000003',
    'a5e00004-0000-0000-0000-000000000004',
    'a5e00005-0000-0000-0000-000000000005',
    'a5e00006-0000-0000-0000-000000000006',
    'a5e00007-0000-0000-0000-000000000007',
    'a5e00008-0000-0000-0000-000000000008',
    'a5e00009-0000-0000-0000-000000000009',
    'a5e0000a-0000-0000-0000-000000000010',
    'a5e0000b-0000-0000-0000-000000000011',
    'a5e0000c-0000-0000-0000-000000000012',
    'a5e0000d-0000-0000-0000-000000000013',
    'a5e0000e-0000-0000-0000-000000000014',
    'a5e0000f-0000-0000-0000-000000000015',
    'a5e00010-0000-0000-0000-000000000016',
    'a5e00011-0000-0000-0000-000000000017',
    'a5e00012-0000-0000-0000-000000000018',
    'a5e00013-0000-0000-0000-000000000019',
    'a5e00014-0000-0000-0000-000000000020',
    'a5e00015-0000-0000-0000-000000000021',
    'a5e00016-0000-0000-0000-000000000022',
    'a5e00017-0000-0000-0000-000000000023',
    'a5e00018-0000-0000-0000-000000000024',
    'a5e00019-0000-0000-0000-000000000025'
  ];
  user_id uuid;
  i int;
BEGIN
  FOR i IN 1..array_length(user_ids, 1) LOOP
    user_id := user_ids[i];
    INSERT INTO auth.users (id, email, encrypted_password, email_confirmed_at, created_at, updated_at, raw_app_meta_data, raw_user_meta_data, aud, role)
    VALUES (
      user_id,
      'customer' || i || '@buzzly.test',
      crypt('password123', gen_salt('bf')),
      now(),
      now(),
      now(),
      '{"provider":"email","providers":["email"]}',
      '{}',
      'authenticated',
      'authenticated'
    )
    ON CONFLICT (id) DO NOTHING;
  END LOOP;
END $$;

-- 5. Get plan IDs for subscriptions
DO $$
DECLARE
  free_plan_id uuid;
  pro_plan_id uuid;
  team_plan_id uuid;
  thb_currency_id uuid;
  pm_id uuid;
BEGIN
  -- Get existing plan IDs
  SELECT id INTO free_plan_id FROM public.subscription_plans WHERE slug = 'free' LIMIT 1;
  SELECT id INTO pro_plan_id FROM public.subscription_plans WHERE slug = 'pro' LIMIT 1;
  SELECT id INTO team_plan_id FROM public.subscription_plans WHERE slug = 'team' LIMIT 1;
  SELECT id INTO thb_currency_id FROM public.currencies WHERE code = 'THB' LIMIT 1;
  SELECT id INTO pm_id FROM public.payment_methods LIMIT 1;
  
  IF free_plan_id IS NULL OR pro_plan_id IS NULL THEN
    RAISE NOTICE 'Subscription plans not found, skipping subscription creation';
    RETURN;
  END IF;

  -- Insert subscriptions (25 active subscriptions)
  INSERT INTO public.subscriptions (id, user_id, plan_id, status, billing_cycle, current_period_start, current_period_end)
  VALUES 
    ('a2000001-0000-0000-0000-000000000001', 'a5e00001-0000-0000-0000-000000000001', pro_plan_id, 'active', 'monthly', '2024-01-15', '2025-01-15'),
    ('a2000002-0000-0000-0000-000000000002', 'a5e00002-0000-0000-0000-000000000002', free_plan_id, 'active', 'monthly', '2024-02-10', '2025-02-10'),
    ('a2000003-0000-0000-0000-000000000003', 'a5e00003-0000-0000-0000-000000000003', pro_plan_id, 'active', 'monthly', '2024-03-05', '2025-03-05'),
    ('a2000004-0000-0000-0000-000000000004', 'a5e00004-0000-0000-0000-000000000004', COALESCE(team_plan_id, pro_plan_id), 'active', 'yearly', '2024-01-20', '2025-01-20'),
    ('a2000005-0000-0000-0000-000000000005', 'a5e00005-0000-0000-0000-000000000005', free_plan_id, 'active', 'monthly', '2024-04-12', '2025-04-12'),
    ('a2000006-0000-0000-0000-000000000006', 'a5e00006-0000-0000-0000-000000000006', pro_plan_id, 'active', 'monthly', '2024-05-08', '2025-05-08'),
    ('a2000007-0000-0000-0000-000000000007', 'a5e00007-0000-0000-0000-000000000007', pro_plan_id, 'active', 'monthly', '2024-06-14', '2025-06-14'),
    ('a2000008-0000-0000-0000-000000000008', 'a5e00008-0000-0000-0000-000000000008', free_plan_id, 'active', 'monthly', '2024-07-03', '2025-07-03'),
    ('a2000009-0000-0000-0000-000000000009', 'a5e00009-0000-0000-0000-000000000009', COALESCE(team_plan_id, pro_plan_id), 'active', 'yearly', '2024-02-28', '2025-02-28'),
    ('a200000a-0000-0000-0000-000000000010', 'a5e0000a-0000-0000-0000-000000000010', pro_plan_id, 'active', 'monthly', '2024-08-22', '2025-08-22'),
    ('a200000b-0000-0000-0000-000000000011', 'a5e0000b-0000-0000-0000-000000000011', free_plan_id, 'active', 'monthly', '2024-09-17', '2025-09-17'),
    ('a200000c-0000-0000-0000-000000000012', 'a5e0000c-0000-0000-0000-000000000012', pro_plan_id, 'active', 'monthly', '2024-10-05', '2025-10-05'),
    ('a200000d-0000-0000-0000-000000000013', 'a5e0000d-0000-0000-0000-000000000013', COALESCE(team_plan_id, pro_plan_id), 'active', 'yearly', '2024-03-18', '2025-03-18'),
    ('a200000e-0000-0000-0000-000000000014', 'a5e0000e-0000-0000-0000-000000000014', free_plan_id, 'active', 'monthly', '2024-11-11', '2025-11-11'),
    ('a200000f-0000-0000-0000-000000000015', 'a5e0000f-0000-0000-0000-000000000015', pro_plan_id, 'active', 'monthly', '2024-12-02', '2025-12-02'),
    ('a2000010-0000-0000-0000-000000000016', 'a5e00010-0000-0000-0000-000000000016', pro_plan_id, 'active', 'monthly', '2024-04-25', '2025-04-25'),
    ('a2000011-0000-0000-0000-000000000017', 'a5e00011-0000-0000-0000-000000000017', free_plan_id, 'active', 'monthly', '2024-05-30', '2025-05-30'),
    ('a2000012-0000-0000-0000-000000000018', 'a5e00012-0000-0000-0000-000000000018', COALESCE(team_plan_id, pro_plan_id), 'active', 'yearly', '2024-06-20', '2025-06-20'),
    ('a2000013-0000-0000-0000-000000000019', 'a5e00013-0000-0000-0000-000000000019', pro_plan_id, 'active', 'monthly', '2024-07-15', '2025-07-15'),
    ('a2000014-0000-0000-0000-000000000020', 'a5e00014-0000-0000-0000-000000000020', free_plan_id, 'active', 'monthly', '2024-08-08', '2025-08-08'),
    ('a2000015-0000-0000-0000-000000000021', 'a5e00015-0000-0000-0000-000000000021', pro_plan_id, 'active', 'monthly', '2024-09-01', '2025-09-01'),
    ('a2000016-0000-0000-0000-000000000022', 'a5e00016-0000-0000-0000-000000000022', COALESCE(team_plan_id, pro_plan_id), 'active', 'yearly', '2024-10-12', '2025-10-12'),
    ('a2000017-0000-0000-0000-000000000023', 'a5e00017-0000-0000-0000-000000000023', free_plan_id, 'active', 'monthly', '2024-11-25', '2025-11-25'),
    ('a2000018-0000-0000-0000-000000000024', 'a5e00018-0000-0000-0000-000000000024', pro_plan_id, 'active', 'monthly', '2024-12-18', '2025-12-18'),
    ('a2000019-0000-0000-0000-000000000025', 'a5e00019-0000-0000-0000-000000000025', COALESCE(team_plan_id, pro_plan_id), 'active', 'yearly', '2024-07-28', '2025-07-28')
  ON CONFLICT (id) DO NOTHING;

  -- Insert payment transactions for these subscriptions
  INSERT INTO public.payment_transactions (id, user_id, subscription_id, payment_method_id, amount, currency_id, status, transaction_type)
  SELECT 
    gen_random_uuid(),
    s.user_id,
    s.id,
    pm_id,
    CASE 
      WHEN sp.slug = 'free' THEN 0
      WHEN sp.slug = 'pro' AND s.billing_cycle = 'monthly' THEN 2990
      WHEN sp.slug = 'pro' AND s.billing_cycle = 'yearly' THEN 29900
      WHEN sp.slug = 'team' AND s.billing_cycle = 'monthly' THEN 4990
      WHEN sp.slug = 'team' AND s.billing_cycle = 'yearly' THEN 49900
      ELSE 2990
    END,
    thb_currency_id,
    'completed',
    'subscription'
  FROM public.subscriptions s
  JOIN public.subscription_plans sp ON s.plan_id = sp.id
  WHERE s.id::text LIKE 'a2%' 
  ON CONFLICT DO NOTHING;
END $$;

